import{c as t,Q as a,j as o,m as n}from"./chunks/framework.DpF7k2f3.js";const c=JSON.parse('{"title":"Chapter 3: Your Entry Roadmap","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en/part1-cognition/chapter3.md","filePath":"en/part1-cognition/chapter3.md"}'),r={name:"en/part1-cognition/chapter3.md"};function i(s,e,d,l,p,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="chapter-3-your-entry-roadmap" tabindex="-1">Chapter 3: Your Entry Roadmap <a class="header-anchor" href="#chapter-3-your-entry-roadmap" aria-label="Permalink to &quot;Chapter 3: Your Entry Roadmap&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>In the first two chapters, we solved the problems of &quot;can I enter&quot; and &quot;should I enter now.&quot; This chapter is the conclusion of the Cognition section, and I&#39;ll give you a <strong>roadmap you can follow directly</strong>.</p><p>After reading this chapter, you will know:</p><ul><li>What type of entry candidate you are (backend/full-stack/beginner/student), and your unique strategy</li><li>8-week intensive entry plan, with precise weekly tasks</li><li>6-month deep-dive advancement plan, from &quot;can do the work&quot; to &quot;standing firm&quot;</li><li>How to choose learning resources, what&#39;s worth paying for, what&#39;s free and sufficient</li></ul><p>After reading this chapter, you should close the book, open your computer, and start executing.</p><hr><h2 id="_3-1-four-types-of-entry-candidates-and-their-strategies" tabindex="-1">3.1 Four Types of Entry Candidates and Their Strategies <a class="header-anchor" href="#_3-1-four-types-of-entry-candidates-and-their-strategies" aria-label="Permalink to &quot;3.1 Four Types of Entry Candidates and Their Strategies&quot;">​</a></h2><p>Before drawing your roadmap, I need to ask you a question: <strong>Who are you?</strong></p><p>There&#39;s no standard answer for entering the AI field. Different starting points determine different optimal paths.</p><p>I divide entry candidates into four categories, each with its own advantages and pitfalls. Find your category and your corresponding strategy.</p><hr><h3 id="profile-1-backend-developers-transitioning-to-ai-development" tabindex="-1">Profile 1: Backend Developers Transitioning to AI Development <a class="header-anchor" href="#profile-1-backend-developers-transitioning-to-ai-development" aria-label="Permalink to &quot;Profile 1: Backend Developers Transitioning to AI Development&quot;">​</a></h3><p><strong>Who You Are</strong></p><p>You have 1-5 years of backend development experience, possibly Java, Go, or Python. You&#39;ve written APIs, built services, and worked with databases. For you, writing code isn&#39;t the problem—the question is &quot;how do I write code on the AI side?&quot;</p><p><strong>Your Advantage</strong></p><p>Your biggest advantage is <strong>engineering capability</strong>. Many people think transitioning to AI means abandoning engineering skills, but it&#39;s actually the opposite—the most scarce talent in 2026 is people who can reliably run AI models in production.</p><hr><blockquote><p><strong>Full translation coming soon. You can read the Chinese version in the meantime.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part1-cognition/chapter3.html">阅读中文版</a></p></blockquote>',19)])])}const g=t(r,[["render",i]]);export{c as __pageData,g as default};
